import{_ as o,o as a,c as n,a2 as e}from"./chunks/framework.B72_uj9U.js";const d=JSON.parse('{"title":"JSON Schema Basics","description":"Understand JSON Schema fundamentals needed to describe tool input parameters to the LLM.","frontmatter":{"title":"JSON Schema Basics","description":"Understand JSON Schema fundamentals needed to describe tool input parameters to the LLM."},"headers":[],"relativePath":"learn/project/04-building-a-tool-system/03-json-schema-basics.md","filePath":"learn/project/04-building-a-tool-system/03-json-schema-basics.md"}'),t={name:"learn/project/04-building-a-tool-system/03-json-schema-basics.md"};function l(p,s,c,r,i,y){return a(),n("div",null,[...s[0]||(s[0]=[e(`<h1 id="json-schema-basics" tabindex="-1">JSON Schema Basics <a class="header-anchor" href="#json-schema-basics" aria-label="Permalink to &quot;JSON Schema Basics&quot;">​</a></h1><blockquote><p><strong>What you&#39;ll learn:</strong></p><ul><li>How JSON Schema describes the shape, types, and constraints of a JSON object</li><li>The key schema keywords you need for tool definitions: type, properties, required, description, and enum</li><li>How the Anthropic API uses the input_schema field to tell the model what arguments a tool accepts</li></ul></blockquote><p>Before you can define tool schemas in Rust code, you need to understand the format itself. JSON Schema is a specification for describing the structure of JSON data. It is what the Anthropic API uses to tell the model what arguments each tool accepts. If you get the schema wrong, the model will send malformed inputs. If you get it right, the model will reliably produce exactly the JSON your tool expects.</p><h2 id="what-json-schema-does" tabindex="-1">What JSON Schema Does <a class="header-anchor" href="#what-json-schema-does" aria-label="Permalink to &quot;What JSON Schema Does&quot;">​</a></h2><p>JSON Schema answers one question: &quot;Is this JSON value valid?&quot; You write a schema that describes what valid data looks like -- its types, required fields, allowed values, constraints. Then you (or a validation library) check whether a given JSON value conforms to that schema.</p><p>For tool definitions, the schema serves a dual purpose. First, it tells the model what arguments to produce: &quot;this tool takes a <code>path</code> string and an optional <code>line_number</code> integer.&quot; Second, your agent code can validate the model&#39;s output against the schema before executing the tool, catching errors early.</p><p>Here is a minimal example. This schema describes an object with one required string field:</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;object&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">properties</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#9399B2;">    &quot;</span><span style="color:#89B4FA;">path</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;string&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">description</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;The file path to read.&quot;</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#9399B2;">  },</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">required</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;path&quot;</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>A JSON value like <code>{&quot;path&quot;: &quot;src/main.rs&quot;}</code> is valid. A value like <code>{&quot;path&quot;: 42}</code> is invalid (wrong type). A value like <code>{}</code> is invalid (missing required field).</p><h2 id="the-keywords-you-need" tabindex="-1">The Keywords You Need <a class="header-anchor" href="#the-keywords-you-need" aria-label="Permalink to &quot;The Keywords You Need&quot;">​</a></h2><p>JSON Schema has dozens of keywords, but tool definitions only use a handful. Here are the ones you will use throughout this book.</p><h3 id="type" tabindex="-1"><code>type</code> <a class="header-anchor" href="#type" aria-label="Permalink to &quot;\`type\`&quot;">​</a></h3><p>Specifies the expected JSON type. The values relevant to tool schemas are:</p><table tabindex="0"><thead><tr><th>Type</th><th>JSON Example</th><th>Rust Equivalent</th></tr></thead><tbody><tr><td><code>&quot;string&quot;</code></td><td><code>&quot;hello&quot;</code></td><td><code>String</code> or <code>&amp;str</code></td></tr><tr><td><code>&quot;number&quot;</code></td><td><code>3.14</code></td><td><code>f64</code></td></tr><tr><td><code>&quot;integer&quot;</code></td><td><code>42</code></td><td><code>i64</code></td></tr><tr><td><code>&quot;boolean&quot;</code></td><td><code>true</code></td><td><code>bool</code></td></tr><tr><td><code>&quot;object&quot;</code></td><td><code>{&quot;key&quot;: &quot;val&quot;}</code></td><td><code>serde_json::Map</code></td></tr><tr><td><code>&quot;array&quot;</code></td><td><code>[1, 2, 3]</code></td><td><code>Vec&lt;T&gt;</code></td></tr><tr><td><code>&quot;null&quot;</code></td><td><code>null</code></td><td><code>Option::None</code></td></tr></tbody></table><p>Every tool&#39;s top-level schema should have <code>&quot;type&quot;: &quot;object&quot;</code> because the Anthropic API sends tool inputs as JSON objects.</p><h3 id="properties" tabindex="-1"><code>properties</code> <a class="header-anchor" href="#properties" aria-label="Permalink to &quot;\`properties\`&quot;">​</a></h3><p>Defines the fields an object can contain. Each property has its own sub-schema:</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;object&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">properties</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#9399B2;">    &quot;</span><span style="color:#89B4FA;">path</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;string&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">description</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;The file path to read.&quot;</span></span>
<span class="line"><span style="color:#9399B2;">    },</span></span>
<span class="line"><span style="color:#9399B2;">    &quot;</span><span style="color:#89B4FA;">offset</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;integer&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">description</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;Line number to start reading from (1-based).&quot;</span></span>
<span class="line"><span style="color:#9399B2;">    },</span></span>
<span class="line"><span style="color:#9399B2;">    &quot;</span><span style="color:#89B4FA;">limit</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;integer&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">description</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;Maximum number of lines to return.&quot;</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#9399B2;">  }</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>The model reads the <code>description</code> for each property to understand what value to pass. Good property descriptions are concise but specific -- &quot;The file path to read&quot; beats &quot;path&quot; and &quot;The absolute or relative path to the file you want to read, as a string&quot; is unnecessarily verbose.</p><h3 id="required" tabindex="-1"><code>required</code> <a class="header-anchor" href="#required" aria-label="Permalink to &quot;\`required\`&quot;">​</a></h3><p>An array of field names that must be present. Fields not listed in <code>required</code> are optional:</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;object&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">properties</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#9399B2;">    &quot;</span><span style="color:#89B4FA;">path</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;string&quot;</span><span style="color:#9399B2;">,</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">description</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;File path.&quot;</span><span style="color:#9399B2;"> },</span></span>
<span class="line"><span style="color:#9399B2;">    &quot;</span><span style="color:#89B4FA;">offset</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;integer&quot;</span><span style="color:#9399B2;">,</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">description</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;Start line.&quot;</span><span style="color:#9399B2;"> }</span></span>
<span class="line"><span style="color:#9399B2;">  },</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">required</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;path&quot;</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>Here, <code>path</code> must be provided. <code>offset</code> is optional -- if the model does not include it, your tool should use a sensible default (like starting from line 1).</p><h3 id="description" tabindex="-1"><code>description</code> <a class="header-anchor" href="#description" aria-label="Permalink to &quot;\`description\`&quot;">​</a></h3><p>A human-readable (and LLM-readable) explanation. You can use <code>description</code> at the property level and at the top level of the schema:</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;object&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">description</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;Input for the read_file tool.&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">properties</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#9399B2;">    &quot;</span><span style="color:#89B4FA;">path</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;string&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">description</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;Absolute or relative path to the file.&quot;</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#9399B2;">  },</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">required</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;path&quot;</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>While the top-level <code>description</code> on the schema is less important (the tool&#39;s own <code>description</code> field handles that), property-level descriptions are critical. They are the model&#39;s primary guide for constructing correct arguments.</p><h3 id="enum" tabindex="-1"><code>enum</code> <a class="header-anchor" href="#enum" aria-label="Permalink to &quot;\`enum\`&quot;">​</a></h3><p>Restricts a string (or other type) to a fixed set of values:</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;string&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">enum</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;read&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;write&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;append&quot;</span><span style="color:#9399B2;">],</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">description</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;The file operation mode.&quot;</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>This tells the model it must choose one of the three listed values. Enums are useful for tools that have a mode parameter, like a file tool that can read or write, or a search tool that can search by name or by content.</p><h3 id="items" tabindex="-1"><code>items</code> <a class="header-anchor" href="#items" aria-label="Permalink to &quot;\`items\`&quot;">​</a></h3><p>Describes the elements of an array:</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;object&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">properties</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#9399B2;">    &quot;</span><span style="color:#89B4FA;">paths</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;array&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">items</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;string&quot;</span><span style="color:#9399B2;"> },</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">description</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;List of file paths to process.&quot;</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#9399B2;">  }</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>You will use this less often, but it matters for tools that accept multiple inputs, like a batch file reader.</p><h2 id="how-the-anthropic-api-uses-schemas" tabindex="-1">How the Anthropic API Uses Schemas <a class="header-anchor" href="#how-the-anthropic-api-uses-schemas" aria-label="Permalink to &quot;How the Anthropic API Uses Schemas&quot;">​</a></h2><p>When you send a request to the Anthropic Messages API, the <code>tools</code> array contains objects with three fields:</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">tools</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> [</span></span>
<span class="line"><span style="color:#9399B2;">    {</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">name</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;read_file&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">description</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;Read the contents of a file at the given path.&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">input_schema</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#9399B2;">        &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;object&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">        &quot;</span><span style="color:#89B4FA;">properties</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#9399B2;">          &quot;</span><span style="color:#89B4FA;">path</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#9399B2;">            &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;string&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">            &quot;</span><span style="color:#89B4FA;">description</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;The file path to read.&quot;</span></span>
<span class="line"><span style="color:#9399B2;">          }</span></span>
<span class="line"><span style="color:#9399B2;">        },</span></span>
<span class="line"><span style="color:#9399B2;">        &quot;</span><span style="color:#89B4FA;">required</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;path&quot;</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#9399B2;">      }</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#9399B2;">  ]</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>The <code>input_schema</code> is the JSON Schema you just learned about. The model uses <code>name</code> and <code>description</code> to decide <em>whether</em> to call the tool, and <code>input_schema</code> to decide <em>what arguments</em> to pass.</p><p>When the model decides to call this tool, it produces a <code>tool_use</code> content block:</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;tool_use&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">id</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;toolu_01A2B3C4D5&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">name</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;read_file&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">input</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#9399B2;">    &quot;</span><span style="color:#89B4FA;">path</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;src/main.rs&quot;</span></span>
<span class="line"><span style="color:#9399B2;">  }</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>Notice that <code>input</code> conforms to the <code>input_schema</code> -- it is an object with a <code>path</code> string. The model learned this shape from the schema you provided. This is why accurate schemas matter: an incorrect schema leads to incorrect inputs.</p><div class="custom-block python"><p class="custom-block-title">Coming from Python</p><p>In Python, you might use Pydantic to define tool input models and then call <code>.model_json_schema()</code> to get the JSON Schema automatically:</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">from</span><span style="color:#CDD6F4;"> pydantic </span><span style="color:#CBA6F7;">import</span><span style="color:#CDD6F4;"> BaseModel</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> Field</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">class</span><span style="color:#F9E2AF;font-style:italic;"> ReadFileInput</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">BaseModel</span><span style="color:#9399B2;">):</span></span>
<span class="line"><span style="color:#CDD6F4;">    path</span><span style="color:#9399B2;">:</span><span style="color:#FAB387;font-style:italic;"> str</span><span style="color:#94E2D5;"> =</span><span style="color:#89B4FA;"> Field</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">description</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;The file path to read.&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CDD6F4;">schema </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> ReadFileInput</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">model_json_schema</span><span style="color:#9399B2;">()</span></span></code></pre></div><p>Rust has a similar option with the <code>schemars</code> crate, which derives JSON Schema from Rust types. You will see both approaches -- manual construction with <code>serde_json::json!</code> and automatic derivation with <code>schemars</code> -- in the next subchapter.</p></div><h2 id="schemas-in-rust-with-serde-json" tabindex="-1">Schemas in Rust with serde_json <a class="header-anchor" href="#schemas-in-rust-with-serde-json" aria-label="Permalink to &quot;Schemas in Rust with serde_json&quot;">​</a></h2><p>You do not need a separate JSON Schema library to <em>construct</em> schemas. The <code>serde_json::json!</code> macro lets you write JSON literals directly in Rust code:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">use</span><span style="color:#F9E2AF;"> serde_json</span><span style="color:#94E2D5;">::</span><span style="color:#9399B2;">{</span><span style="color:#CDD6F4;">json</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> Value</span><span style="color:#9399B2;">};</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">fn</span><span style="color:#89B4FA;font-style:italic;"> read_file_schema</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;font-style:italic;"> Value</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    json!</span><span style="color:#9399B2;">({</span></span>
<span class="line"><span style="color:#A6E3A1;">        &quot;type&quot;</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> &quot;object&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#A6E3A1;">        &quot;properties&quot;</span><span style="color:#94E2D5;">:</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#A6E3A1;">            &quot;path&quot;</span><span style="color:#94E2D5;">:</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#A6E3A1;">                &quot;type&quot;</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> &quot;string&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#A6E3A1;">                &quot;description&quot;</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> &quot;The file path to read.&quot;</span></span>
<span class="line"><span style="color:#9399B2;">            },</span></span>
<span class="line"><span style="color:#A6E3A1;">            &quot;offset&quot;</span><span style="color:#94E2D5;">:</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#A6E3A1;">                &quot;type&quot;</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> &quot;integer&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#A6E3A1;">                &quot;description&quot;</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> &quot;Line number to start reading from (1-based).&quot;</span></span>
<span class="line"><span style="color:#9399B2;">            },</span></span>
<span class="line"><span style="color:#A6E3A1;">            &quot;limit&quot;</span><span style="color:#94E2D5;">:</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#A6E3A1;">                &quot;type&quot;</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> &quot;integer&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#A6E3A1;">                &quot;description&quot;</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> &quot;Maximum number of lines to return.&quot;</span></span>
<span class="line"><span style="color:#9399B2;">            }</span></span>
<span class="line"><span style="color:#9399B2;">        },</span></span>
<span class="line"><span style="color:#A6E3A1;">        &quot;required&quot;</span><span style="color:#94E2D5;">:</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;path&quot;</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#9399B2;">    })</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">fn</span><span style="color:#89B4FA;font-style:italic;"> main</span><span style="color:#9399B2;">()</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> schema </span><span style="color:#94E2D5;">=</span><span style="color:#89B4FA;font-style:italic;"> read_file_schema</span><span style="color:#9399B2;">();</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    println!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;"> serde_json</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">to_string_pretty</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#CDD6F4;">schema</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">unwrap</span><span style="color:#9399B2;">());</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>The <code>json!</code> macro returns a <code>serde_json::Value</code>, which is exactly the type your <code>Tool::input_schema()</code> method returns. This approach is straightforward: what you see in the macro is what gets sent to the API. The downside is that the schema is not validated at compile time -- a typo in a keyword like <code>&quot;properteis&quot;</code> will not cause a compiler error. You catch those during testing.</p><h2 id="a-complete-schema-example" tabindex="-1">A Complete Schema Example <a class="header-anchor" href="#a-complete-schema-example" aria-label="Permalink to &quot;A Complete Schema Example&quot;">​</a></h2><p>Here is a more realistic schema for a shell execution tool. It demonstrates several keywords working together:</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;object&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">properties</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#9399B2;">    &quot;</span><span style="color:#89B4FA;">command</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;string&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">description</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;The shell command to execute.&quot;</span></span>
<span class="line"><span style="color:#9399B2;">    },</span></span>
<span class="line"><span style="color:#9399B2;">    &quot;</span><span style="color:#89B4FA;">working_directory</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;string&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">description</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;Directory to run the command in. Defaults to the project root.&quot;</span></span>
<span class="line"><span style="color:#9399B2;">    },</span></span>
<span class="line"><span style="color:#9399B2;">    &quot;</span><span style="color:#89B4FA;">timeout_seconds</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;integer&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">description</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;Maximum time in seconds before the command is killed. Defaults to 30.&quot;</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#9399B2;">  },</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">required</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;command&quot;</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>This schema tells the model: you <em>must</em> provide a <code>command</code> string; you <em>may</em> provide a <code>working_directory</code> and a <code>timeout_seconds</code>. The descriptions guide the model&#39;s choices -- it knows the default timeout is 30 seconds, so it will only override it for commands expected to run longer.</p><div class="custom-block wild"><p class="custom-block-title">In the Wild</p><p>Claude Code&#39;s tool schemas are notably detailed. The <code>Bash</code> tool&#39;s schema includes descriptions like &quot;The command to execute in the shell. Must be a valid bash command.&quot; and constraints on maximum output length. These detailed schemas reduce tool-call errors significantly -- the model rarely sends malformed input when the schema clearly describes what is expected.</p></div><h2 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h2><ul><li>JSON Schema describes the structure of JSON data using keywords like <code>type</code>, <code>properties</code>, <code>required</code>, <code>description</code>, and <code>enum</code>.</li><li>Every tool schema has <code>&quot;type&quot;: &quot;object&quot;</code> at the top level because tool inputs are always JSON objects.</li><li>The <code>required</code> array distinguishes mandatory fields from optional ones. Optional fields should have sensible defaults in your tool implementation.</li><li>Property-level <code>description</code> values are critical -- they guide the model in constructing correct arguments, functioning as mini-prompts.</li><li>The <code>serde_json::json!</code> macro lets you write schemas as JSON literals in Rust code, returning the <code>serde_json::Value</code> type your trait expects.</li></ul>`,54)])])}const B=o(t,[["render",l]]);export{d as __pageData,B as default};
